public class Main {

    public static double celsiusToFahrenheit(double c) {
        return (c * 9.0 / 5.0) + 32;
    }

    public static double fahrenheitToCelsius(double f) {
        return (f - 32) * 5.0 / 9.0;
    }

    public static void main(String[] args) {
        double fResult = celsiusToFahrenheit(100.0);
        double cResult = fahrenheitToCelsius(98.6);
        System.out.printf("100.0C = %.1fF%n", fResult);
        System.out.printf("98.6F = %.1fC%n",  cResult);
    }
}

