public class Main {

    // Overload 1: String only
    public static void describe(String name) {
        System.out.println("Name: " + name);
    }

    // Overload 2: String + int
    public static void describe(String name, int age) {
        System.out.println("Name: " + name + ", Age: " + age);
    }

    // Overload 3: String + int + String
    public static void describe(String name, int age, String city) {
        System.out.println("Name: " + name +
                           ", Age: " + age +
                           ", City: " + city);
    }

    // Overloaded area() methods
    public static double area(double radius) {
        return Math.PI * radius * radius;   // circle
    }

    public static double area(double width, double height) {
        return width * height;              // rectangle
    }

    public static void main(String[] args) {
        // Compiler picks the right overload automatically
        describe("Rahul");
        describe("Priya", 22);
        describe("Amit",  28, "Mumbai");

        System.out.printf("Circle area    : %.2f%n", area(5.0));
        System.out.printf("Rectangle area : %.2f%n", area(4.0, 6.0));
    }
}

